	GradeA      Grade = iota // 0.93+
	GradeAMinus              // 0.90+
	GradeBPlus               // 0.87+
	GradeB                   // 0.80+
	GradeC                   // 0.70+
	GradeD                   // 0.60+
	GradeF                   // < 0.60
	GradeNA                  // not applicable (unsupported language)
)

var gradeStrings = map[Grade]string{
	GradeA:      "A",
	GradeAMinus: "A-",
	GradeBPlus:  "B+",
	GradeB:      "B",
	GradeC:      "C",
	GradeD:      "D",
	GradeF:      "F",
	GradeNA:     "N/A",
}

// String returns the letter grade string.
func (g Grade) String() string {
	if s, ok := gradeStrings[g]; ok {
		return s
	}
	return fmt.Sprintf("Grade(%d)", g)
}

// GradeFromScore converts a numeric score (0.0–1.0) to a letter grade.
func GradeFromScore(score float64) Grade {
	switch {
	case score >= 0.93:
		return GradeA
	case score >= 0.90:
		return GradeAMinus
	case score >= 0.87:
		return GradeBPlus
	case score >= 0.80:
		return GradeB
	case score >= 0.70:
		return GradeC
	case score >= 0.60:
		return GradeD
	default:
		return GradeF
	}
}

// GradeFromScoreWithSupport converts a numeric score to a letter grade,
// returning GradeNA when the language is unsupported and score is 0.
func GradeFromScoreWithSupport(score float64, supported bool) Grade {
	if !supported && score == 0 {
		return GradeNA
	}
	return GradeFromScore(score)
}

